mapper.select:
SELECT s.proxy_server_id AS system_server_id, s.proxy_server_name AS system_server_name, s.proxy_server_host AS system_server_host, s.proxy_server_port AS system_server_port, s.proxy_server_type AS system_server_type, s.proxy_server_context_path AS system_server_context_path, s.proxy_server_status AS system_server_status, s.proxy_server_description AS system_server_description, s.proxy_server_config AS system_server_config, s.proxy_server_auto_start AS system_server_auto_start, s.proxy_server_max_connections AS system_server_max_connections, s.proxy_server_timeout AS system_server_timeout, s.create_name, s.create_by, s.create_time, s.update_name, s.update_by, s.update_time, (SELECT COUNT(*) FROM proxy_server_setting ss WHERE ss.proxy_server_setting_server_id = s.proxy_server_id) AS filter_count FROM proxy_server s
AND s.proxy_server_name LIKE CONCAT('%', #{entity.systemServerName}, '%')
AND s.proxy_server_host LIKE CONCAT('%', #{entity.systemServerHost}, '%')
AND s.proxy_server_port = #{entity.systemServerPort}
AND s.proxy_server_status = #{entity.systemServerStatus.name}
AND s.proxy_server_type = #{entity.systemServerType}
ORDER BY s.create_time DESC

SELECT * FROM proxy_server 
WHERE proxy_server_type = #{serverType}
ORDER BY create_time DESC

SELECT * FROM proxy_server 
WHERE proxy_server_status = #{status}
ORDER BY create_time DESC

mapper.update:
UPDATE proxy_server 
SET proxy_server_status = #{status}, update_time = NOW()
WHERE proxy_server_id = #{serverId}
